- New Year's Day in 2016 refers to January 1, 2016;
- Active users are those with is_active = 1;
- A badge of honor refers to a commendation.

sql:
SELECT user_id, MAX(last_commendation_date) AS latest_commendation_date
FROM user_commendations
GROUP BY user_id;

SELECT commendation_count AS total_commendations
FROM user_commendations
WHERE user_id = 1;

SELECT commendation_count
FROM user_commendations
WHERE user_id = 1;

SELECT status_id, commendation_count
FROM status_commendations
ORDER BY commendation_count DESC;

SELECT COUNT(commendation_id) AS total_commendations
FROM commendations
WHERE user_id = 0;
